"""Process derivation.

A process is identified by (pid, source_system, cwd) for now; slice B will
refine pid-reuse separation via claude_log_pid_deaths. Processes layer on
top of sessions — the process's "current session" state is the latest
session's state, and process detail nests sessions[].
"""

import aiosqlite

from agentpulse.api.v2.ids import derive_process_id
from agentpulse.api.v2.queries._helpers import (
    active_agent_states,
    agents_for_session,
    latest_hook_for_session,
)
from agentpulse.api.v2.queries.sessions import get_session_by_id
from agentpulse.api.v2.state import compute_effective_state, derive_state


async def _process_identity_tuples(
    db: aiosqlite.Connection,
) -> list[tuple[int, str, str]]:
    """Distinct (pid, source_system, cwd) tuples across both log tables."""
    cursor = await db.execute("""
        SELECT pid, source_system, cwd FROM claude_log_hooks
        UNION
        SELECT pid, source_system, cwd FROM claude_log_statuslines
        """)
    rows = await cursor.fetchall()
    return [(r["pid"], r["source_system"], r["cwd"]) for r in rows]


async def _hook_window(
    db: aiosqlite.Connection, *, pid: int, source_system: str, cwd: str
) -> dict:
    cursor = await db.execute(
        """
        SELECT MIN(received_at) AS started_at,
               MAX(received_at) AS last_activity_at,
               COUNT(*) AS event_count
        FROM claude_log_hooks
        WHERE pid = ? AND source_system = ? AND cwd = ?
        """,
        (pid, source_system, cwd),
    )
    row = await cursor.fetchone()
    return dict(row) if row else {}


async def _statusline_window(
    db: aiosqlite.Connection, *, pid: int, source_system: str, cwd: str
) -> dict:
    cursor = await db.execute(
        """
        SELECT MIN(received_at) AS started_at,
               MAX(received_at) AS last_activity_at,
               MAX(cost_usd) AS cost_usd
        FROM claude_log_statuslines
        WHERE pid = ? AND source_system = ? AND cwd = ?
        """,
        (pid, source_system, cwd),
    )
    row = await cursor.fetchone()
    return dict(row) if row else {}


async def _latest_hook(
    db: aiosqlite.Connection, *, pid: int, source_system: str, cwd: str
) -> dict | None:
    cursor = await db.execute(
        """
        SELECT * FROM claude_log_hooks
        WHERE pid = ? AND source_system = ? AND cwd = ?
        ORDER BY received_at DESC, id DESC LIMIT 1
        """,
        (pid, source_system, cwd),
    )
    row = await cursor.fetchone()
    return dict(row) if row else None


async def _latest_statusline(
    db: aiosqlite.Connection, *, pid: int, source_system: str, cwd: str
) -> dict | None:
    cursor = await db.execute(
        """
        SELECT * FROM claude_log_statuslines
        WHERE pid = ? AND source_system = ? AND cwd = ?
        ORDER BY received_at DESC, id DESC LIMIT 1
        """,
        (pid, source_system, cwd),
    )
    row = await cursor.fetchone()
    return dict(row) if row else None


async def _session_ids_for_process(
    db: aiosqlite.Connection, *, pid: int, source_system: str, cwd: str
) -> list[str]:
    cursor = await db.execute(
        """
        SELECT session_id FROM claude_log_hooks
        WHERE pid = ? AND source_system = ? AND cwd = ?
        UNION
        SELECT session_id FROM claude_log_statuslines
        WHERE pid = ? AND source_system = ? AND cwd = ?
        """,
        (pid, source_system, cwd, pid, source_system, cwd),
    )
    rows = await cursor.fetchall()
    return [r["session_id"] for r in rows]


async def _cost_by_day(
    db: aiosqlite.Connection, *, pid: int, source_system: str, cwd: str
) -> dict[str, float]:
    """Per-day cost increment derived from cumulative cost_usd statuslines.

    cost_usd is monotonic over a process lifetime, so the day's increment is
    `MAX(cost_usd today) - MAX(cost_usd through yesterday)`. Server local time
    determines the day buckets per database.md.
    """
    cursor = await db.execute(
        """
        SELECT date(received_at, 'unixepoch', 'localtime') AS day,
               MAX(cost_usd) AS day_max
        FROM claude_log_statuslines
        WHERE pid = ? AND source_system = ? AND cwd = ?
              AND cost_usd IS NOT NULL
        GROUP BY day
        ORDER BY day
        """,
        (pid, source_system, cwd),
    )
    rows = [dict(r) for r in await cursor.fetchall()]
    out: dict[str, float] = {}
    prev = 0.0
    for r in rows:
        day_max = float(r["day_max"]) if r["day_max"] is not None else prev
        out[r["day"]] = round(day_max - prev, 6)
        prev = day_max
    return out


async def _derive_process(
    db: aiosqlite.Connection, *, pid: int, source_system: str, cwd: str
) -> dict | None:
    """Build one ProcessResponse-shaped dict for a (pid, source_system, cwd)."""
    hook_win = await _hook_window(db, pid=pid, source_system=source_system, cwd=cwd)
    sl_win = await _statusline_window(db, pid=pid, source_system=source_system, cwd=cwd)

    candidates = [
        x
        for x in (hook_win.get("started_at"), sl_win.get("started_at"))
        if x is not None
    ]
    if not candidates:
        return None
    started_at = min(candidates)
    last_activity_at = max(
        x
        for x in (hook_win.get("last_activity_at"), sl_win.get("last_activity_at"))
        if x is not None
    )

    process_id = derive_process_id(
        source_system=source_system, pid=pid, cwd=cwd, earliest_received_at=started_at
    )

    latest_hook = await _latest_hook(db, pid=pid, source_system=source_system, cwd=cwd)
    latest_sl = await _latest_statusline(
        db, pid=pid, source_system=source_system, cwd=cwd
    )

    current_session_id = (
        latest_hook["session_id"]
        if latest_hook
        else (latest_sl["session_id"] if latest_sl else None)
    )

    derived_state: str | None = None
    if current_session_id:
        # Use the latest hook for the *current session* (not the latest hook
        # for the process), so a process whose latest activity is on a new
        # session reflects that session's state.
        current_session_latest = await latest_hook_for_session(
            db, session_id=current_session_id
        )
        session_state = None
        if current_session_latest is not None:
            session_state = derive_state(
                current_session_latest["event_name"],
                tool_name=current_session_latest["tool_name"] or "",
            )
        agents = await agents_for_session(db, session_id=current_session_id)
        derived_state = compute_effective_state(
            session_state, active_agent_states(agents)
        )

    sessions = await _session_ids_for_process(
        db, pid=pid, source_system=source_system, cwd=cwd
    )
    cost_by_day = await _cost_by_day(db, pid=pid, source_system=source_system, cwd=cwd)

    return {
        "process_id": process_id,
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
        "platform": "claude",
        "entrypoint": (latest_hook or {}).get("entrypoint"),
        "claude_version": (latest_hook or {}).get("claude_version")
        or (latest_sl or {}).get("claude_version"),
        "permission_mode": (latest_hook or {}).get("permission_mode"),
        "started_at": started_at,
        "last_activity_at": last_activity_at,
        "ended_at": None,  # filled in by slice B (pid_deaths)
        "pid_alive": True,  # likewise
        "current_session_id": current_session_id,
        "derived_state": derived_state,
        "cost_usd": sl_win.get("cost_usd"),
        "cost_by_day": cost_by_day,
        "total_input_tokens": (latest_sl or {}).get("total_input_tokens"),
        "total_output_tokens": (latest_sl or {}).get("total_output_tokens"),
        "lines_added": (latest_sl or {}).get("lines_added"),
        "lines_removed": (latest_sl or {}).get("lines_removed"),
        "model_id": (latest_sl or {}).get("model_id"),
        "model_name": (latest_sl or {}).get("model_name"),
        "session_count": len(sessions),
        # In A3 each (pid, source_system, cwd) is one process and one pid, so
        # epoch_count == session_count. Slice B+D refine this.
        "epoch_count": len(sessions),
        "sessions": None,
        "_session_ids": sessions,  # internal; consumers use sessions list
    }


async def get_processes(
    db: aiosqlite.Connection,
    *,
    active_only: bool = False,
    source_system: str | None = None,
    cwd: str | None = None,
    since: float | None = None,
) -> list[dict]:
    """List processes derived from log tables. Ordered by last_activity_at DESC."""
    keys = await _process_identity_tuples(db)
    processes: list[dict] = []
    for pid, ss, cwd_ in keys:
        proc = await _derive_process(db, pid=pid, source_system=ss, cwd=cwd_)
        if proc is None:
            continue
        if source_system is not None and proc["source_system"] != source_system:
            continue
        if cwd is not None and proc["cwd"] != cwd:
            continue
        if since is not None and proc["last_activity_at"] < since:
            continue
        if active_only and not proc["pid_alive"]:
            continue
        processes.append(proc)
    processes.sort(key=lambda p: p["last_activity_at"], reverse=True)
    return processes


async def get_process_by_id(
    db: aiosqlite.Connection, *, process_id: str
) -> dict | None:
    """Single process by derived id, with sessions[] populated."""
    procs = await get_processes(db)
    match = next((p for p in procs if p["process_id"] == process_id), None)
    if match is None:
        return None
    sessions: list[dict] = []
    for sid in match["_session_ids"]:
        sess = await get_session_by_id(db, session_id=sid)
        if sess is not None:
            sessions.append(sess)
    match["sessions"] = sessions
    return match
